+import { join, resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+const isPlainObject = (value: unknown): value is Record<string, unknown> =>
+  !!value && typeof value === "object" &&
+  (Object.getPrototypeOf(value) === Object.prototype ||
+    Object.getPrototypeOf(value) === null);
+
+const camelCase = (key: string): string =>
+  key.replace(/-([a-zA-Z0-9])/g, (_match, letter) => letter.toUpperCase());
+
+/** Flatten nested configuration objects to the option notation used by flags. */
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (isPlainObject(item)) {
+      Object.assign(result, flattenConfig(item, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [index, line] of content.split(/\\r?\
/).entries()) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = line.indexOf("=");
+    if (separator < 1) {
+      throw new Error(`Invalid RC entry on line ${index + 1}.`);
+    }
+    const key = line.slice(0, separator).trim();
+    let value = line.slice(separator + 1).trim();
+    if (!key) throw new Error(`Invalid RC entry on line ${index + 1}.`);
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error(`Unterminated quoted value on line ${index + 1}.`);
+      }
+      value = value.slice(1, -1);
+    } else if (value === "true") {
+      result[camelCase(key)] = true;
+      continue;
+    } else if (value === "false") {
+      result[camelCase(key)] = false;
+      continue;
+    } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[-+]?\\d+)?$/i.test(value)) {
+      result[camelCase(key)] = Number(value);
+      continue;
+    }
+    result[camelCase(key)] = value;
+  }
+  return result;
+}
+
+function filename(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parse(content: string, path: string, options: ConfigOptions): Record<string, unknown> {
+  try {
+    const parsed = options.parser
+      ? options.parser(content)
+      : path.endsWith(".json")
+      ? JSON.parse(content)
+      : path.endsWith(".rc")
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(parsed)) throw new Error("Configuration must be a plain object.");
+    return flattenConfig(parsed);
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [Deno.cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const found: Array<{ path: string; values: Record<string, unknown> }> = [];
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = resolve(join(searchPath, filename(options.name, format)));
+      try {
+        const content = await Deno.readTextFile(path);
+        found.push({ path, values: parse(content, path, options) });
+        break;
+      } catch (error) {
+        if (error instanceof ConfigParseError) throw error;
+        if (error instanceof Deno.errors.NotFound) continue;
+        throw error;
+      }
+    }
+    if (found.length && !options.mergeConfigs) break;
+  }
+
+  if (!found.length) return { values: {} };
+  const values = options.mergeConfigs
+    ? found.reduceRight<Record<string, unknown>>(
+      (merged, config) => ({ ...merged, ...config.values }),
+      {},
+    )
+    : found[0].values;
+  return { path: found[0].path, values };
+}
